import React, { useState } from "react";
import { useAuth } from "./hooks/useAuth";
import LoginPage from "./pages/LoginPage";
import HomePage from "./pages/HomePage";
import AcademicPage from "./pages/AcademicPage";
import FoodPage from "./pages/FoodPage";
import LaundryPage from "./pages/LaundryPage";
import ComplaintPage from "./pages/ComplaintPage";
import Navbar from "./components/Navbar";

export default function App() {
  const { user, login, logout, isLoading, error: authError } = useAuth();
  const [currentPage, setCurrentPage] = useState("home");

  if (!user) {
    return <LoginPage onLogin={login} isLoading={isLoading} authError={authError} />;
  }

  return (
    <div className="min-h-screen bg-gradient-to-b from-white/85 via-white/90 to-white/95">
      <Navbar
        user={user}
        logout={logout}
        currentPage={currentPage}
        setCurrentPage={setCurrentPage}
      />

      <main className="max-w-7xl mx-auto px-4 py-8">
        {currentPage === "home" && <HomePage />}
        {currentPage === "academic" && <AcademicPage />}
        {currentPage === "food" && <FoodPage />}
        {currentPage === "laundry" && <LaundryPage />}
        {currentPage === "complaint" && <ComplaintPage />}
      </main>
    </div>
  );
}
